  USING ((EXISTS ( SELECT 1 FROM ((tasks t JOIN projects proj ON ((proj.id = t.project_id))) JOIN property_definitions pd ON ((pd.id = task_property_values.property_id))) WHERE ((t.id = task_property_values.task_id) AND (proj.initiative_id = pd.initiative_id) AND public.initiative_access(pd.initiative_id, (NULLIF(current_setting('app.current_user_id'::text, true), ''::text))::integer, true)))));

